module RefModule(
    input [3:0] D,
    input Clk,reset,load,
    output reg [3:0] Q
    );  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge Clk or posedge dbg_halt)
    if (reset)
    begin
        Q <= 4'b0;
    end else if (load)
    begin
        Q <= D;
    end
endmodule
